/* =====================================================
   PWA — SERVICE WORKER + MANIFEST ROBUSTO
===================================================== */
function instalarPWA() {
  // Manifest mejorado
  const manifest = {
    name: 'PrestControl',
    short_name: 'PrestControl',
    description: 'Gestión de préstamos y cuotas — funciona sin internet',
    start_url: './',
    display: 'standalone',
    background_color: '#0F172A',
    theme_color: '#3B82F6',
    orientation: 'portrait',
    categories: ['finance', 'productivity'],
    icons: [
      { src:"data:image/png;base64,", sizes:'192x192', type:'image/png', purpose:'any maskable' },
      { src:"data:image/png;base64,", sizes:'512x512', type:'image/png', purpose:'any maskable' }
    ]
  };
  const blob = new Blob([JSON.stringify(manifest)], { type:'application/json' });
  document.getElementById('pwa-manifest').setAttribute('href', URL.createObjectURL(blob));

  // Registrar Service Worker inline (solo si no estamos en file://)
  if ('serviceWorker' in navigator && location.protocol !== 'file:') {
    const swCode = `
const CACHE = 'prestcontrol-v1';
const ASSETS = ['./', './index.html'];
self.addEventListener('install', e => { e.waitUntil(caches.open(CACHE).then(c => c.addAll(ASSETS)).catch(()=>{})); self.skipWaiting(); });
self.addEventListener('activate', e => { e.waitUntil(caches.keys().then(ks => Promise.all(ks.filter(k=>k!==CACHE).map(k=>caches.delete(k))))); self.clients.claim(); });
self.addEventListener('fetch', e => {
  if (e.request.method !== 'GET') return;
  if (e.request.url.includes('googleapis.com') || e.request.url.includes('accounts.google.com')) return;
  e.respondWith(fetch(e.request).catch(() => caches.match(e.request)));
});`;
    const swBlob = new Blob([swCode], { type:'application/javascript' });
    const swUrl  = URL.createObjectURL(swBlob);
    navigator.serviceWorker.register(swUrl).catch(() => {});
  }
}

// Prompt de instalación PWA
let deferredInstallPrompt = null;
window.addEventListener('beforeinstallprompt', e => {
  e.preventDefault();
  deferredInstallPrompt = e;
  // Mostrar banner suave después de 3s si no está instalado
  setTimeout(() => {
    if (deferredInstallPrompt && appDesbloqueada) {
      toast('📲 Podés instalar la app — tocá ⚙️ Config');
    }
  }, 3000);
});

async function instalarAppEnCelular() {
  if (deferredInstallPrompt) {
    deferredInstallPrompt.prompt();
    const { outcome } = await deferredInstallPrompt.userChoice;
    if (outcome === 'accepted') toast('✅ App instalada correctamente');
    deferredInstallPrompt = null;
  } else {
    toast('ℹ️ Chrome → ⋮ → "Agregar a pantalla de inicio"');
  }
}

/* =====================================================
   REFRESH
===================================================== */
async function refreshApp() {
  const btn = document.getElementById('refresh-btn');
  if (btn) { btn.style.opacity = '.4'; btn.style.pointerEvents = 'none'; }
  try {
    await autoUpdateEstados();
    await updateBadges();
    await renderPage(curPage);
    toast('✅ Actualizado');
    if (appDesbloqueada && drivePendingSync) driveSave();
  } finally {
    setTimeout(() => {
      if (btn) { btn.style.opacity = ''; btn.style.pointerEvents = ''; }
    }, 800);
  }
}

